import { useEffect, useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Button } from '@/components/ui/button';

interface Staff {
  id: number;
  firstName: string;
  lastName: string;
  email: string;
  phone: string;
  role: string;
  department: string;
  joinDate: string;
}

export default function StaffDetail() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [staff, setStaff] = useState<Staff | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // TODO: Replace with actual API call
    const mockStaff: Staff = {
      id: Number(id),
      firstName: 'John',
      lastName: 'Doe',
      email: 'john@example.com',
      phone: '+1234567890',
      role: 'Manager',
      department: 'IT',
      joinDate: '2023-01-15',
    };
    
    setStaff(mockStaff);
    setLoading(false);
  }, [id]);

  if (loading) return <div className="p-6">Loading...</div>;
  if (!staff) return <div className="p-6">Staff member not found</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">{staff.firstName} {staff.lastName}</h1>
        <Button variant="outline" onClick={() => navigate('/staff')}>Back</Button>
      </div>

      <div className="grid gap-6 md:grid-cols-2">
        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Personal Information</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Email</p>
              <p className="font-medium">{staff.email}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Phone</p>
              <p className="font-medium">{staff.phone}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Join Date</p>
              <p className="font-medium">{new Date(staff.joinDate).toLocaleDateString()}</p>
            </div>
          </div>
        </div>

        <div className="p-4 border rounded-lg">
          <h3 className="font-semibold mb-4">Work Information</h3>
          <div className="space-y-3">
            <div>
              <p className="text-sm text-gray-600">Role</p>
              <p className="font-medium">{staff.role}</p>
            </div>
            <div>
              <p className="text-sm text-gray-600">Department</p>
              <p className="font-medium">{staff.department}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="flex gap-2">
        <Button>Edit</Button>
        <Button variant="destructive">Delete</Button>
      </div>
    </div>
  );
}
